def solve(*args):
    if not args or len(args) < 2:
        return "Invalid input"

    project_id, user_id = args[0], args[1]

    if not isinstance(project_id, int) or not isinstance(user_id, int):
        return "Invalid input types"

    # Simulated permissions check
    permissions = {
        1: [101, 102],  # Project ID 1 has access for User IDs 101 and 102
        2: [103]       # Project ID 2 has access for User ID 103
    }

    if project_id in permissions and user_id in permissions[project_id]:
        return "Access granted"
    else:
        return "Access denied"
